[
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_process_sale(p_contact_id integer, p_total_amount numeric, p_discount numeric, p_payment_method character varying, p_receipt_token character varying, p_deposit_account_id integer, p_items jsonb)\n RETURNS integer\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_sale_id INT;\r\n    item JSONB;\r\nBEGIN\r\n    -- 1. Create Sale Record\r\n    INSERT INTO sales (contact_id, total_amount, discount, payment_method, public_receipt_token)\r\n    VALUES (p_contact_id, p_total_amount, p_discount, p_payment_method, p_receipt_token)\r\n    RETURNING sale_id INTO v_sale_id;\r\n\r\n    -- 2. Loop through JSON items\r\n    FOR item IN SELECT * FROM jsonb_array_elements(p_items) LOOP\r\n        -- A. Insert Sale Item\r\n        INSERT INTO sale_item (sale_id, product_id, inventory_id, quantity, unit_price, subtotal)\r\n        VALUES (\r\n            v_sale_id, \r\n            (item->>'product_id')::INT, \r\n            (item->>'inventory_id')::INT, \r\n            (item->>'quantity')::INT, \r\n            (item->>'unit_price')::DECIMAL,\r\n            ((item->>'quantity')::INT * (item->>'unit_price')::DECIMAL)\r\n        );\r\n\r\n        -- B. Mark Inventory as SOLD (if serialized or bulk logic)\r\n        -- (Simple version: just update status for serialized)\r\n        IF (item->>'inventory_id') IS NOT NULL THEN\r\n            UPDATE inventory SET status = 'SOLD' WHERE inventory_id = (item->>'inventory_id')::INT;\r\n        END IF;\r\n    END LOOP;\r\n\r\n    -- 3. Financial Handling\r\n    IF p_payment_method = 'DUE' AND p_contact_id IS NOT NULL THEN\r\n        -- Option A: Ledger Sale -> Update Contact Balance (They owe us)\r\n        UPDATE contacts SET account_balance = account_balance + p_total_amount WHERE contact_id = p_contact_id;\r\n    ELSIF p_deposit_account_id IS NOT NULL THEN\r\n        -- Option B: Cash/Bank Sale -> Record Income Transaction\r\n        INSERT INTO transaction (transaction_type, amount, to_account_id, contact_id, description)\r\n        VALUES ('RECEIVE', p_total_amount, p_deposit_account_id, p_contact_id, 'Sale #' || v_sale_id);\r\n    END IF;\r\n\r\n    RETURN v_sale_id;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_update_bank_balance()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n    -- Money Coming IN (RECEIVE, INVESTMENT, TRANSFER) → credit to_account\r\n    IF NEW.transaction_type::text IN ('RECEIVE', 'INVESTMENT', 'TRANSFER', 'SALE', 'INCOME') THEN\r\n        IF NEW.to_account_id IS NOT NULL THEN\r\n            UPDATE banking_account\r\n            SET current_balance = current_balance + NEW.amount\r\n            WHERE account_id = NEW.to_account_id;\r\n        END IF;\r\n    END IF;\r\n\r\n    -- Money Going OUT (PAYMENT, TRANSFER, EXPENSE) → debit from_account\r\n    IF NEW.transaction_type::text IN ('PAYMENT', 'TRANSFER', 'EXPENSE') THEN\r\n        IF NEW.from_account_id IS NOT NULL THEN\r\n\r\n            -- Check for sufficient funds\r\n            PERFORM 1 FROM banking_account\r\n            WHERE account_id = NEW.from_account_id\r\n              AND current_balance < NEW.amount;\r\n\r\n            IF FOUND THEN\r\n                RAISE EXCEPTION 'Insufficient funds: Transaction amount % exceeds current balance.', NEW.amount;\r\n            END IF;\r\n\r\n            UPDATE banking_account\r\n            SET current_balance = current_balance - NEW.amount\r\n            WHERE account_id = NEW.from_account_id;\r\n        END IF;\r\n    END IF;\r\n\r\n    RETURN NEW;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_update_contact_ledger()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n    IF NEW.contact_id IS NOT NULL THEN\r\n\r\n        -- RECEIVE / INCOME / SALE → customer paid → balance decreases\r\n        IF NEW.transaction_type::text IN ('RECEIVE', 'INCOME', 'SALE') THEN\r\n            UPDATE contacts\r\n            SET account_balance = account_balance - NEW.amount\r\n            WHERE contact_id = NEW.contact_id;\r\n\r\n        -- PAYMENT / EXPENSE → we paid supplier → payable increases\r\n        ELSIF NEW.transaction_type::text IN ('PAYMENT', 'EXPENSE') THEN\r\n            UPDATE contacts\r\n            SET account_balance = account_balance + NEW.amount\r\n            WHERE contact_id = NEW.contact_id;\r\n        END IF;\r\n\r\n    END IF;\r\n\r\n    RETURN NEW;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.proc_record_login(p_email character varying, p_success boolean, p_failure_reason character varying DEFAULT NULL::character varying, p_ip_address character varying DEFAULT NULL::character varying, p_user_agent character varying DEFAULT NULL::character varying)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_user_id INTEGER := NULL;\r\nBEGIN\r\n    SELECT user_id INTO v_user_id\r\n    FROM public.user_account\r\n    WHERE email = p_email;\r\n\r\n    IF p_success AND v_user_id IS NOT NULL THEN\r\n        UPDATE public.user_account\r\n        SET last_login = CURRENT_TIMESTAMP\r\n        WHERE user_id = v_user_id;\r\n    END IF;\r\n\r\n    INSERT INTO public.user_login_log\r\n        (user_id, email_used, success, failure_reason, ip_address, user_agent)\r\n    VALUES\r\n        (v_user_id, p_email, p_success, p_failure_reason, p_ip_address, p_user_agent);\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_create_sale(p_contact_id integer, p_total_amount numeric, p_discount numeric, p_payment_method text, p_receipt_token text, p_account_id integer, p_sale_date timestamp with time zone, p_items jsonb, p_created_by integer DEFAULT NULL::integer)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_sale_id integer;\r\n    v_item    jsonb;\r\nBEGIN\r\n    -- Publish caller's user_id so fn_after_sale_insert can read it\r\n    PERFORM set_config('app.current_user_id', COALESCE(p_created_by::text, ''), true);\r\n\r\n    INSERT INTO sales (contact_id, total_amount, discount, payment_method, public_receipt_token, sale_date, account_id)\r\n    VALUES (p_contact_id, p_total_amount, p_discount, p_payment_method, p_receipt_token, p_sale_date, p_account_id)\r\n    RETURNING sale_id INTO v_sale_id;\r\n\r\n    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)\r\n    LOOP\r\n        INSERT INTO sale_item (sale_id, product_id, inventory_id, quantity, unit_price, subtotal)\r\n        VALUES (\r\n            v_sale_id,\r\n            (v_item->>'product_id')::integer,\r\n            (v_item->>'inventory_id')::integer,\r\n            (v_item->>'quantity')::integer,\r\n            (v_item->>'unit_price')::numeric,\r\n            (v_item->>'subtotal')::numeric\r\n        );\r\n    END LOOP;\r\n\r\n    RETURN jsonb_build_object('sale_id', v_sale_id, 'public_receipt_token', p_receipt_token);\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_check_brute_force()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_fail_count INTEGER;\r\nBEGIN\r\n    IF NEW.success = false AND NEW.user_id IS NOT NULL THEN\r\n\r\n        SELECT COUNT(*) INTO v_fail_count\r\n        FROM public.user_login_log\r\n        WHERE user_id = NEW.user_id\r\n          AND success = false\r\n          AND login_time > NOW() - INTERVAL '15 minutes';\r\n\r\n        IF v_fail_count >= 5 THEN\r\n            UPDATE public.user_account\r\n            SET is_active = false\r\n            WHERE user_id = NEW.user_id;\r\n\r\n            INSERT INTO public.system_activity_log\r\n                (action, module, target_table, target_id, description)\r\n            VALUES (\r\n                'AUTO_LOCK',\r\n                'SECURITY',\r\n                'user_account',\r\n                NEW.user_id,\r\n                'Account auto-locked after ' || v_fail_count ||\r\n                ' failed login attempts within 15 minutes.'\r\n            );\r\n        END IF;\r\n    END IF;\r\n\r\n    RETURN NULL;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_create_product_with_attributes(p_product_name text, p_category_id integer, p_brand text DEFAULT NULL::text, p_selling_price_estimate numeric DEFAULT NULL::numeric, p_has_serial_number boolean DEFAULT false, p_attributes jsonb DEFAULT '[]'::jsonb)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_product_id integer;\r\n    v_attr       jsonb;\r\n    v_product    jsonb;\r\nBEGIN\r\n    -- 1. Insert the product\r\n    INSERT INTO product (product_name, category_id, brand, selling_price_estimate, has_serial_number)\r\n    VALUES (p_product_name, p_category_id, p_brand, p_selling_price_estimate, p_has_serial_number)\r\n    RETURNING product_id INTO v_product_id;\r\n\r\n    -- 2. Insert attribute values (if any)\r\n    FOR v_attr IN SELECT * FROM jsonb_array_elements(p_attributes)\r\n    LOOP\r\n        INSERT INTO product_attribute_value (product_id, attribute_id, attribute_value)\r\n        VALUES (\r\n            v_product_id,\r\n            (v_attr->>'attribute_id')::integer,\r\n            v_attr->>'value'\r\n        )\r\n        ON CONFLICT (product_id, attribute_id) DO UPDATE\r\n            SET attribute_value = EXCLUDED.attribute_value;\r\n    END LOOP;\r\n\r\n    -- 3. Return full product row as jsonb\r\n    SELECT row_to_json(p)::jsonb INTO v_product\r\n    FROM product p\r\n    WHERE p.product_id = v_product_id;\r\n\r\n    RETURN v_product;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_create_category_with_attributes(p_category_name text, p_description text DEFAULT NULL::text, p_attributes jsonb DEFAULT '[]'::jsonb)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_category_id integer;\r\n    v_attr        jsonb;\r\n    v_result      jsonb;\r\nBEGIN\r\n    -- 1. Insert the category\r\n    INSERT INTO category (category_name, description)\r\n    VALUES (p_category_name, p_description)\r\n    RETURNING category_id INTO v_category_id;\r\n\r\n    -- 2. Insert attribute definitions (if any)\r\n    FOR v_attr IN SELECT * FROM jsonb_array_elements(p_attributes)\r\n    LOOP\r\n        INSERT INTO category_attribute (category_id, attribute_name, data_type, is_required)\r\n        VALUES (\r\n            v_category_id,\r\n            v_attr->>'attribute_name',\r\n            COALESCE(v_attr->>'data_type', 'VARCHAR'),\r\n            COALESCE((v_attr->>'is_required')::boolean, false)\r\n        )\r\n        ON CONFLICT (category_id, attribute_name) DO NOTHING;\r\n    END LOOP;\r\n\r\n    -- 3. Return full category row as jsonb\r\n    SELECT row_to_json(c)::jsonb INTO v_result\r\n    FROM category c\r\n    WHERE c.category_id = v_category_id;\r\n\r\n    RETURN v_result;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_touch_general_settings()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n    NEW.updated_at = CURRENT_TIMESTAMP;\r\n    RETURN NEW;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_get_dashboard_stats()\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_product_count  bigint;\r\n    v_customer_count bigint;\r\n    v_total_balance  numeric;\r\nBEGIN\r\n    SELECT COUNT(*) INTO v_product_count FROM product;\r\n\r\n    SELECT COUNT(*) INTO v_customer_count\r\n    FROM contacts\r\n    WHERE contact_type IN ('CUSTOMER', 'BOTH');\r\n\r\n    SELECT COALESCE(SUM(current_balance), 0) INTO v_total_balance\r\n    FROM banking_account;\r\n\r\n    RETURN jsonb_build_object(\r\n        'totalProducts',  v_product_count,\r\n        'totalCustomers', v_customer_count,\r\n        'totalBalance',   ROUND(v_total_balance, 2)\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_get_contact_stats(p_contact_id integer)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_contact         jsonb;\r\n    v_total_sales     bigint;\r\n    v_total_spent     numeric;\r\n    v_total_trans     bigint;\r\nBEGIN\r\n    -- Fetch the contact row\r\n    SELECT row_to_json(c)::jsonb INTO v_contact\r\n    FROM contacts c\r\n    WHERE c.contact_id = p_contact_id;\r\n\r\n    IF v_contact IS NULL THEN\r\n        RAISE EXCEPTION 'CONTACT_NOT_FOUND: Contact % does not exist', p_contact_id;\r\n    END IF;\r\n\r\n    -- Aggregate sales data\r\n    SELECT COUNT(*), COALESCE(SUM(total_amount), 0)\r\n    INTO v_total_sales, v_total_spent\r\n    FROM sales\r\n    WHERE contact_id = p_contact_id;\r\n\r\n    -- Count transactions\r\n    SELECT COUNT(*) INTO v_total_trans\r\n    FROM transaction\r\n    WHERE contact_id = p_contact_id;\r\n\r\n    RETURN v_contact || jsonb_build_object(\r\n        'stats', jsonb_build_object(\r\n            'totalSales',        v_total_sales,\r\n            'totalSpent',        v_total_spent,\r\n            'totalTransactions', v_total_trans\r\n        )\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_get_contact_history(p_contact_id integer)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_history jsonb;\r\nBEGIN\r\n    SELECT jsonb_agg(row ORDER BY row.date DESC)\r\n    INTO v_history\r\n    FROM (\r\n        -- Transactions\r\n        SELECT\r\n            t.transaction_id                AS id,\r\n            'TRANSACTION'                   AS type,\r\n            t.transaction_type,\r\n            t.amount,\r\n            t.description,\r\n            t.transaction_date              AS date\r\n        FROM transaction t\r\n        WHERE t.contact_id = p_contact_id\r\n\r\n        UNION ALL\r\n\r\n        -- Sales\r\n        SELECT\r\n            s.sale_id                       AS id,\r\n            'SALE'                          AS type,\r\n            'SALE'                          AS transaction_type,\r\n            s.total_amount                  AS amount,\r\n            'Invoice #' || s.sale_id        AS description,\r\n            s.sale_date                     AS date\r\n        FROM sales s\r\n        WHERE s.contact_id = p_contact_id\r\n    ) AS row;\r\n\r\n    RETURN COALESCE(v_history, '[]'::jsonb);\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_log_module_toggle()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n    IF OLD.is_enabled IS DISTINCT FROM NEW.is_enabled THEN\r\n        INSERT INTO public.system_activity_log\r\n            (user_id, action, module, target_table, target_id, old_values, new_values, description)\r\n        VALUES (\r\n            NEW.updated_by,\r\n            CASE WHEN NEW.is_enabled THEN 'MODULE_ENABLED' ELSE 'MODULE_DISABLED' END,\r\n            'SETTINGS',\r\n            'system_config',\r\n            NEW.config_id,\r\n            jsonb_build_object('is_enabled', OLD.is_enabled, 'module_name', OLD.module_name),\r\n            jsonb_build_object('is_enabled', NEW.is_enabled, 'module_name', NEW.module_name),\r\n            'Module \"' || NEW.display_name || '\" was ' ||\r\n            CASE WHEN NEW.is_enabled THEN 'ENABLED' ELSE 'DISABLED' END\r\n        );\r\n    END IF;\r\n    RETURN NULL;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_is_module_enabled(p_module_name character varying)\n RETURNS boolean\n LANGUAGE plpgsql\n STABLE\nAS $function$\r\nDECLARE\r\n    v_enabled BOOLEAN;\r\nBEGIN\r\n    SELECT is_enabled INTO v_enabled\r\n    FROM public.system_config\r\n    WHERE module_name = p_module_name;\r\n\r\n    -- If module doesn't exist in config, default to enabled\r\n    RETURN COALESCE(v_enabled, true);\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_get_general_settings()\n RETURNS TABLE(company_name character varying, company_email character varying, company_phone character varying, company_address text, company_website character varying, currency_code character varying, currency_symbol character varying, currency_position character varying, logo_url text, favicon_url text, social_banner_url text)\n LANGUAGE sql\n STABLE\nAS $function$\r\n    SELECT\r\n        company_name, company_email, company_phone,\r\n        company_address, company_website,\r\n        currency_code, currency_symbol, currency_position,\r\n        logo_url, favicon_url, social_banner_url\r\n    FROM public.general_settings\r\n    WHERE id = 1;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.proc_toggle_module(p_acting_user_id integer, p_enable boolean, p_module_name character varying)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_acting_role  public.employee_role;\r\n    v_is_core      BOOLEAN;\r\n    v_current      BOOLEAN;\r\nBEGIN\r\n    -- Permission check: only ADMIN can toggle modules\r\n    SELECT e.role INTO v_acting_role\r\n    FROM user_account ua\r\n    JOIN employee e ON e.employee_id = ua.employee_id\r\n    WHERE ua.user_id = p_acting_user_id;\r\n\r\n    IF v_acting_role != 'ADMIN' THEN\r\n        RAISE EXCEPTION 'Permission denied: only ADMIN can toggle modules.';\r\n    END IF;\r\n\r\n    -- Fetch module info\r\n    SELECT is_core, is_enabled\r\n    INTO v_is_core, v_current\r\n    FROM public.system_config\r\n    WHERE module_name = p_module_name;\r\n\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Module \"%\" not found.', p_module_name;\r\n    END IF;\r\n\r\n    -- Block disabling core modules\r\n    IF v_is_core = true AND p_enable = false THEN\r\n        RAISE EXCEPTION 'Module \"%\" is a core module and cannot be disabled.', p_module_name;\r\n    END IF;\r\n\r\n    -- Skip if no actual change\r\n    IF v_current = p_enable THEN\r\n        RETURN;\r\n    END IF;\r\n\r\n    -- Apply toggle\r\n    UPDATE public.system_config\r\n    SET\r\n        is_enabled = p_enable,\r\n        updated_at = CURRENT_TIMESTAMP,\r\n        updated_by = p_acting_user_id\r\n    WHERE module_name = p_module_name;\r\n\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.proc_update_general_settings(p_acting_user_id integer, p_company_name character varying DEFAULT NULL::character varying, p_company_email character varying DEFAULT NULL::character varying, p_company_phone character varying DEFAULT NULL::character varying, p_company_address text DEFAULT NULL::text, p_company_website character varying DEFAULT NULL::character varying, p_currency_code character varying DEFAULT NULL::character varying, p_currency_symbol character varying DEFAULT NULL::character varying, p_currency_position character varying DEFAULT NULL::character varying, p_logo_url text DEFAULT NULL::text, p_favicon_url text DEFAULT NULL::text, p_social_banner_url text DEFAULT NULL::text)\n RETURNS boolean\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_role      public.employee_role;\r\n    v_old_vals  JSONB;\r\n    v_new_vals  JSONB;\r\nBEGIN\r\n    SELECT e.role INTO v_role FROM user_account ua\r\n    JOIN employee e ON e.employee_id = ua.employee_id\r\n    WHERE ua.user_id = p_acting_user_id;\r\n\r\n    IF v_role != 'ADMIN' THEN RAISE EXCEPTION 'Permission denied.'; END IF;\r\n\r\n    SELECT to_jsonb(gs) INTO v_old_vals FROM general_settings gs WHERE id = 1;\r\n\r\n    UPDATE public.general_settings SET\r\n        company_name      = COALESCE(p_company_name,      company_name),\r\n        company_email     = COALESCE(p_company_email,     company_email),\r\n        company_phone     = COALESCE(p_company_phone,     company_phone),\r\n        company_address   = COALESCE(p_company_address,   company_address),\r\n        company_website   = COALESCE(p_company_website,   company_website),\r\n        currency_code     = COALESCE(p_currency_code,     currency_code),\r\n        currency_symbol   = COALESCE(p_currency_symbol,   currency_symbol),\r\n        currency_position = COALESCE(p_currency_position, currency_position),\r\n        logo_url          = COALESCE(p_logo_url,          logo_url),\r\n        favicon_url       = COALESCE(p_favicon_url,       favicon_url),\r\n        social_banner_url = COALESCE(p_social_banner_url, social_banner_url),\r\n        updated_at        = CURRENT_TIMESTAMP,\r\n        updated_by        = p_acting_user_id\r\n    WHERE id = 1;\r\n\r\n    SELECT to_jsonb(gs) INTO v_new_vals FROM general_settings gs WHERE id = 1;\r\n\r\n    INSERT INTO public.system_activity_log\r\n        (user_id, action, module, target_table, target_id, old_values, new_values, description)\r\n    VALUES (p_acting_user_id, 'UPDATE', 'SETTINGS', 'general_settings', 1, v_old_vals, v_new_vals, 'General settings updated');\r\n\r\n    RETURN true;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_signup_user(p_email text, p_password_hash text, p_employee_id integer DEFAULT NULL::integer)\n RETURNS jsonb\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_user_count      integer;\r\n    v_employee_id     integer := p_employee_id;\r\n    v_new_user_id     integer;\r\nBEGIN\r\n    SELECT COUNT(*) INTO v_user_count FROM user_account;\r\n\r\n    IF v_user_count = 0 AND v_employee_id IS NULL THEN\r\n        INSERT INTO employee (name, role, designation, email, basic_salary, join_date, is_active)\r\n        VALUES ('Administrator', 'ADMIN', 'System Admin', p_email, 0, CURRENT_DATE, true)\r\n        RETURNING employee_id INTO v_employee_id;\r\n\r\n    ELSIF v_user_count > 0 AND v_employee_id IS NULL THEN\r\n        RAISE EXCEPTION 'EMPLOYEE_REQUIRED: Employee profile is required for non-first users';\r\n    END IF;\r\n\r\n    IF EXISTS (SELECT 1 FROM user_account WHERE email = p_email) THEN\r\n        RAISE EXCEPTION 'EMAIL_EXISTS: Email already registered';\r\n    END IF;\r\n\r\n    IF EXISTS (SELECT 1 FROM user_account WHERE employee_id = v_employee_id) THEN\r\n        RAISE EXCEPTION 'EMPLOYEE_ACCOUNT_EXISTS: This employee profile already has a user account';\r\n    END IF;\r\n\r\n    INSERT INTO user_account (email, password_hash, employee_id, is_active)\r\n    VALUES (p_email, p_password_hash, v_employee_id, true)\r\n    RETURNING user_id INTO v_new_user_id;\r\n\r\n    RETURN jsonb_build_object(\r\n        'user_id',     v_new_user_id,\r\n        'email',       p_email,\r\n        'employee_id', v_employee_id\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_process_warranty_claim(p_claim_id integer, p_replacement_inventory_id integer, p_replacement_coverage character varying, p_processed_by_employee_id integer, p_notes text DEFAULT NULL::text)\n RETURNS json\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_claim                     warranty_claim%ROWTYPE;\r\n    v_config                    product_warranty_config%ROWTYPE;\r\n    v_orig_inv                  inventory%ROWTYPE;\r\n    v_repl_inv                  inventory%ROWTYPE;\r\n    v_orig_sale                 sales%ROWTYPE;\r\n    v_warranty_start            TIMESTAMP;\r\n    v_orig_expires_at           TIMESTAMP;\r\n    v_repl_expires_at           TIMESTAMP;\r\n    v_is_serialized             BOOLEAN;\r\n    v_qty_returned              INT;\r\nBEGIN\r\n    -- ── Load & Validate Claim ──────────────────────────────────────────\r\n    SELECT * INTO v_claim FROM warranty_claim WHERE claim_id = p_claim_id;\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Warranty claim % not found', p_claim_id;\r\n    END IF;\r\n    IF v_claim.status NOT IN ('PENDING', 'APPROVED') THEN\r\n        RAISE EXCEPTION 'Claim % is already in status %. Cannot process.', p_claim_id, v_claim.status;\r\n    END IF;\r\n\r\n    -- ── Load Original Inventory & Product Config ───────────────────────\r\n    SELECT * INTO v_orig_inv FROM inventory WHERE inventory_id = v_claim.original_inventory_id;\r\n    SELECT pwc.* INTO v_config\r\n        FROM product_warranty_config pwc\r\n        WHERE pwc.product_id = v_orig_inv.product_id;\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'No warranty configuration found for product %', v_orig_inv.product_id;\r\n    END IF;\r\n\r\n    v_is_serialized := (v_orig_inv.serial_number IS NOT NULL);\r\n\r\n    -- ── Compute Original Warranty Expiry ───────────────────────────────\r\n    SELECT * INTO v_orig_sale FROM sales WHERE sale_id = v_claim.original_sale_id;\r\n\r\n    IF v_config.warranty_start_rule = 'SALE_DATE' THEN\r\n        v_warranty_start := v_orig_sale.sale_date;\r\n    ELSIF v_config.warranty_start_rule = 'STOCK_DATE' THEN\r\n        v_warranty_start := v_orig_inv.created_at;\r\n    ELSIF v_config.warranty_start_rule = 'MANUFACTURE_DATE' THEN\r\n        -- Use noon UTC on the manufacture date to avoid timezone edge cases\r\n        v_warranty_start := v_orig_inv.manufacture_date::TIMESTAMP;\r\n    ELSE\r\n        v_warranty_start := v_orig_sale.sale_date;\r\n    END IF;\r\n\r\n    v_orig_expires_at := v_warranty_start + (v_config.period_days || ' days')::INTERVAL;\r\n\r\n    -- ── Validate Warranty is Still Active ─────────────────────────────\r\n    IF NOW() > v_orig_expires_at THEN\r\n        RAISE EXCEPTION 'Warranty for inventory % has expired on %',\r\n            v_claim.original_inventory_id, v_orig_expires_at;\r\n    END IF;\r\n\r\n    -- ── Compute Replacement Warranty Expiry ───────────────────────────\r\n    IF p_replacement_coverage = 'FRESH_PERIOD' THEN\r\n        -- Brand-new full period from today\r\n        v_repl_expires_at := NOW() + (v_config.period_days || ' days')::INTERVAL;\r\n    ELSE\r\n        -- REMAINDER: inherit whatever is left on the original window\r\n        v_repl_expires_at := v_orig_expires_at;\r\n    END IF;\r\n\r\n    -- ── Load Replacement Inventory ─────────────────────────────────────\r\n    SELECT * INTO v_repl_inv FROM inventory WHERE inventory_id = p_replacement_inventory_id;\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Replacement inventory item % not found', p_replacement_inventory_id;\r\n    END IF;\r\n    IF v_repl_inv.status != 'IN_STOCK' THEN\r\n        RAISE EXCEPTION 'Replacement inventory item % is not IN_STOCK (current: %)',\r\n            p_replacement_inventory_id, v_repl_inv.status;\r\n    END IF;\r\n\r\n    -- ── Update Original Inventory ──────────────────────────────────────\r\n    IF v_is_serialized THEN\r\n        -- Serialized: mark the whole unit as replaced\r\n        UPDATE inventory\r\n            SET status = 'WARRANTY_REPLACED'\r\n            WHERE inventory_id = v_claim.original_inventory_id;\r\n    ELSE\r\n        -- Non-serialized: the returned qty is whatever was claimed (treat as 1 for now)\r\n        -- Qty update was already handled when the claim was created (returned_inventory_id)\r\n        -- Nothing extra needed here for the original inventory row\r\n        NULL;\r\n    END IF;\r\n\r\n    -- ── Mark Returned Item as WARRANTY_RETURNED (holding pool) ────────\r\n    IF v_claim.returned_inventory_id IS NOT NULL THEN\r\n        UPDATE inventory\r\n            SET status = 'WARRANTY_RETURNED'\r\n            WHERE inventory_id = v_claim.returned_inventory_id;\r\n    END IF;\r\n\r\n    -- ── Update Replacement Inventory Status ────────────────────────────\r\n    -- For serialized: mark it SOLD (it's going to the customer as a replacement)\r\n    -- For non-serialized: quantity was handled at claim creation\r\n    IF v_is_serialized THEN\r\n        UPDATE inventory\r\n            SET status = 'SOLD'\r\n            WHERE inventory_id = p_replacement_inventory_id;\r\n    END IF;\r\n\r\n    -- ── Insert Serial Log (serialized only) ───────────────────────────\r\n    IF v_is_serialized THEN\r\n        INSERT INTO warranty_serial_log (\r\n            claim_id,\r\n            original_serial_number,\r\n            replacement_serial_number,\r\n            original_inventory_id,\r\n            replacement_inventory_id\r\n        ) VALUES (\r\n            p_claim_id,\r\n            v_orig_inv.serial_number,\r\n            v_repl_inv.serial_number,\r\n            v_claim.original_inventory_id,\r\n            p_replacement_inventory_id\r\n        );\r\n    END IF;\r\n\r\n    -- ── Update Claim to COMPLETED ──────────────────────────────────────\r\n    UPDATE warranty_claim SET\r\n        replacement_inventory_id        = p_replacement_inventory_id,\r\n        replacement_coverage_applied    = p_replacement_coverage,\r\n        original_warranty_expires_at    = v_orig_expires_at,\r\n        replacement_warranty_expires_at = v_repl_expires_at,\r\n        status                          = 'COMPLETED',\r\n        processed_by_employee_id        = p_processed_by_employee_id,\r\n        notes                           = COALESCE(p_notes, notes)\r\n    WHERE claim_id = p_claim_id;\r\n\r\n    RETURN json_build_object(\r\n        'claim_id',                       p_claim_id,\r\n        'original_warranty_expires_at',   v_orig_expires_at,\r\n        'replacement_warranty_expires_at', v_repl_expires_at,\r\n        'replacement_coverage_applied',   p_replacement_coverage,\r\n        'is_serialized',                  v_is_serialized\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_finalise_returned_item(p_claim_id integer, p_disposition character varying, p_account_id integer DEFAULT NULL::integer, p_notes text DEFAULT NULL::text)\n RETURNS json\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_claim         warranty_claim%ROWTYPE;\r\n    v_ret_inv       inventory%ROWTYPE;\r\n    v_loss_txn_id   INT;\r\n    v_loss_amount   DECIMAL(15,2);\r\nBEGIN\r\n    -- ── Validate ───────────────────────────────────────────────────────\r\n    SELECT * INTO v_claim FROM warranty_claim WHERE claim_id = p_claim_id;\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Claim % not found', p_claim_id;\r\n    END IF;\r\n    IF v_claim.status != 'COMPLETED' THEN\r\n        RAISE EXCEPTION 'Claim % must be COMPLETED before finalising disposition (current: %)',\r\n            p_claim_id, v_claim.status;\r\n    END IF;\r\n    IF v_claim.returned_item_disposition != 'HOLDING' THEN\r\n        RAISE EXCEPTION 'Claim % disposition is already finalised (%)',\r\n            p_claim_id, v_claim.returned_item_disposition;\r\n    END IF;\r\n\r\n    -- ── Load Returned Inventory ────────────────────────────────────────\r\n    IF v_claim.returned_inventory_id IS NOT NULL THEN\r\n        SELECT * INTO v_ret_inv\r\n            FROM inventory WHERE inventory_id = v_claim.returned_inventory_id;\r\n    END IF;\r\n\r\n    IF p_disposition = 'DISCARDED' THEN\r\n        -- The business absorbed the cost of the item given away.\r\n        -- Loss = purchase_price of the replacement item that was handed out.\r\n        SELECT purchase_price * quantity INTO v_loss_amount\r\n            FROM inventory WHERE inventory_id = v_claim.replacement_inventory_id;\r\n\r\n        IF p_account_id IS NULL THEN\r\n            RAISE EXCEPTION 'p_account_id is required when disposition is DISCARDED';\r\n        END IF;\r\n\r\n        -- Record loss as a PAYMENT transaction (money leaving the business)\r\n        INSERT INTO transaction (\r\n            transaction_type, amount, from_account_id, description, transaction_date\r\n        ) VALUES (\r\n            'PAYMENT',\r\n            v_loss_amount,\r\n            p_account_id,\r\n            'Warranty Loss — Claim #' || p_claim_id || ' — item discarded',\r\n            NOW()\r\n        ) RETURNING transaction_id INTO v_loss_txn_id;\r\n\r\n        -- Update claim\r\n        UPDATE warranty_claim SET\r\n            returned_item_disposition = 'DISCARDED',\r\n            loss_transaction_id       = v_loss_txn_id,\r\n            loss_amount               = v_loss_amount,\r\n            notes                     = COALESCE(p_notes, notes)\r\n        WHERE claim_id = p_claim_id;\r\n\r\n    ELSIF p_disposition = 'SENT_TO_MANUFACTURER' THEN\r\n        -- Item leaves our possession — mark it as WARRANTY_REPLACED\r\n        IF v_claim.returned_inventory_id IS NOT NULL THEN\r\n            UPDATE inventory\r\n                SET status = 'WARRANTY_REPLACED'\r\n                WHERE inventory_id = v_claim.returned_inventory_id;\r\n        END IF;\r\n\r\n        UPDATE warranty_claim SET\r\n            returned_item_disposition = 'SENT_TO_MANUFACTURER',\r\n            notes                     = COALESCE(p_notes, notes)\r\n        WHERE claim_id = p_claim_id;\r\n\r\n    ELSE\r\n        RAISE EXCEPTION 'Invalid disposition value: %. Must be DISCARDED or SENT_TO_MANUFACTURER.', p_disposition;\r\n    END IF;\r\n\r\n    RETURN json_build_object(\r\n        'claim_id',    p_claim_id,\r\n        'disposition', p_disposition,\r\n        'loss_amount', COALESCE(v_loss_amount, 0)\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.proc_toggle_user_account(p_acting_user_id integer, p_target_user_id integer, p_set_active boolean)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_acting_role public.employee_role;\r\nBEGIN\r\n    SELECT e.role INTO v_acting_role\r\n    FROM user_account ua\r\n    JOIN employee e ON e.employee_id = ua.employee_id\r\n    WHERE ua.user_id = p_acting_user_id;\r\n\r\n    IF v_acting_role != 'ADMIN' THEN\r\n        RAISE EXCEPTION 'Permission denied: only ADMIN can toggle accounts.';\r\n    END IF;\r\n\r\n    IF p_acting_user_id = p_target_user_id THEN\r\n        RAISE EXCEPTION 'Cannot deactivate your own account.';\r\n    END IF;\r\n\r\n    UPDATE public.user_account\r\n    SET is_active = p_set_active\r\n    WHERE user_id = p_target_user_id;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_check_warranty_status(p_inventory_id integer)\n RETURNS json\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_inv           inventory%ROWTYPE;\r\n    v_config        product_warranty_config%ROWTYPE;\r\n    v_sale          sales%ROWTYPE;\r\n    v_sale_item     sale_item%ROWTYPE;\r\n    v_warranty_start    TIMESTAMP;\r\n    v_expires_at        TIMESTAMP;\r\n    v_days_remaining    INT;\r\n    v_is_active         BOOLEAN;\r\n    v_is_expiring_soon  BOOLEAN;\r\nBEGIN\r\n    SELECT * INTO v_inv FROM inventory WHERE inventory_id = p_inventory_id;\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Inventory item % not found', p_inventory_id;\r\n    END IF;\r\n\r\n    SELECT pwc.* INTO v_config\r\n        FROM product_warranty_config pwc WHERE pwc.product_id = v_inv.product_id;\r\n    IF NOT FOUND THEN\r\n        RETURN json_build_object('has_warranty', false);\r\n    END IF;\r\n\r\n    -- Find the sale this item was sold in\r\n    SELECT si.* INTO v_sale_item\r\n        FROM sale_item si WHERE si.inventory_id = p_inventory_id LIMIT 1;\r\n    IF FOUND THEN\r\n        SELECT s.* INTO v_sale FROM sales s WHERE s.sale_id = v_sale_item.sale_id;\r\n    END IF;\r\n\r\n    -- Determine warranty start\r\n    IF v_config.warranty_start_rule = 'SALE_DATE' THEN\r\n        v_warranty_start := v_sale.sale_date;\r\n    ELSIF v_config.warranty_start_rule = 'STOCK_DATE' THEN\r\n        v_warranty_start := v_inv.created_at;\r\n    ELSIF v_config.warranty_start_rule = 'MANUFACTURE_DATE' THEN\r\n        v_warranty_start := v_inv.manufacture_date::TIMESTAMP;\r\n    END IF;\r\n\r\n    IF v_warranty_start IS NULL THEN\r\n        RETURN json_build_object('has_warranty', true, 'status', 'UNKNOWN_START_DATE');\r\n    END IF;\r\n\r\n    v_expires_at        := v_warranty_start + (v_config.period_days || ' days')::INTERVAL;\r\n    v_days_remaining    := GREATEST(0, EXTRACT(DAY FROM (v_expires_at - NOW()))::INT);\r\n    v_is_active         := NOW() <= v_expires_at;\r\n    v_is_expiring_soon  := v_is_active AND v_days_remaining <= v_config.expiry_alert_days;\r\n\r\n    RETURN json_build_object(\r\n        'has_warranty',         true,\r\n        'product_id',           v_inv.product_id,\r\n        'inventory_id',         p_inventory_id,\r\n        'serial_number',        v_inv.serial_number,\r\n        'warranty_start_rule',  v_config.warranty_start_rule,\r\n        'warranty_started_at',  v_warranty_start,\r\n        'warranty_expires_at',  v_expires_at,\r\n        'period_days',          v_config.period_days,\r\n        'days_remaining',       v_days_remaining,\r\n        'is_active',            v_is_active,\r\n        'is_expiring_soon',     v_is_expiring_soon,\r\n        'expiry_alert_days',    v_config.expiry_alert_days,\r\n        'sale_id',              v_sale.sale_id,\r\n        'sale_date',            v_sale.sale_date\r\n    );\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_after_sale_insert()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\nDECLARE\n    v_created_by INTEGER;\nBEGIN\n    -- Read caller identity published by sp_create_sale\n    v_created_by := NULLIF(current_setting('app.current_user_id', true), '')::INTEGER;\n\n    -- Decrement inventory\n    UPDATE inventory\n    SET quantity = inventory.quantity - si.quantity,\n        status   = CASE\n                       WHEN (inventory.quantity - si.quantity) <= 0 THEN 'SOLD'\n                       ELSE 'IN_STOCK'\n                   END\n    FROM sale_item si\n    WHERE si.sale_id = NEW.sale_id\n      AND inventory.inventory_id = si.inventory_id;\n\n    -- ALL sales increase the customer's due balance (they owe us for the goods)\n    IF NEW.contact_id IS NOT NULL THEN\n        UPDATE contacts\n        SET account_balance = account_balance + NEW.total_amount\n        WHERE contact_id = NEW.contact_id;\n    END IF;\n\n    -- Create RECEIVE transaction stamped with created_by.\n    -- If they pay by CASH or BANK, the transaction trigger (fn_update_contact_ledger) \n    -- will dynamically subtract the received amount from the due balance, resulting in a net 0 change.\n    IF NEW.payment_method IN ('cash', 'CASH', 'bank', 'BANK') THEN\n        INSERT INTO transaction (\n            transaction_type, amount, to_account_id, contact_id,\n            description, transaction_date, created_by\n        ) VALUES (\n            'RECEIVE', NEW.total_amount, NEW.account_id, NEW.contact_id,\n            'Sale #' || NEW.sale_id, NEW.sale_date, v_created_by\n        );\n    END IF;\n\n    RETURN NEW;\nEND;\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sp_add_stock(p_product_id integer, p_supplier_id integer, p_quantity integer, p_purchase_price numeric, p_selling_price numeric, p_serial_numbers text[] DEFAULT NULL::text[], p_account_id integer DEFAULT NULL::integer, p_created_by integer DEFAULT NULL::integer)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\nDECLARE\n    v_total_cost DECIMAL;\n    v_serial     text;\nBEGIN\n    IF p_serial_numbers IS NOT NULL AND array_length(p_serial_numbers, 1) > 0 THEN\n        -- Serialized product: insert one row per serial number, each with quantity = 1\n        FOREACH v_serial IN ARRAY p_serial_numbers\n        LOOP\n            INSERT INTO inventory (product_id, supplier_id, quantity, purchase_price, selling_price, serial_number, status)\n            VALUES (p_product_id, p_supplier_id, 1, p_purchase_price, p_selling_price, v_serial, 'IN_STOCK');\n        END LOOP;\n    ELSE\n        -- Non-serialized product: insert a single row with the given quantity\n        INSERT INTO inventory (product_id, supplier_id, quantity, purchase_price, selling_price, serial_number, status)\n        VALUES (p_product_id, p_supplier_id, p_quantity, p_purchase_price, p_selling_price, NULL, 'IN_STOCK');\n    END IF;\n\n    -- Calculate total cost (purchase_price * quantity, regardless of serialization)\n    v_total_cost := p_purchase_price * p_quantity;\n\n    -- Set the current user for audit logging\n    PERFORM set_config('app.current_user_id', COALESCE(p_created_by::text, ''), true);\n\n    -- Record purchase as a PAYMENT transaction\n    INSERT INTO transaction (transaction_type, amount, from_account_id, contact_id, description, created_by)\n    VALUES ('PAYMENT', v_total_cost, p_account_id, p_supplier_id,\n            'Stock Purchase: Product ID ' || p_product_id, p_created_by);\nEND;\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.proc_change_employee_role(p_acting_user_id integer, p_target_emp_id integer, p_new_role_id integer)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_acting_role_key VARCHAR;\r\n    v_acting_emp      INTEGER;\r\nBEGIN\r\n    SELECT ua.employee_id, br.role_key\r\n    INTO v_acting_emp, v_acting_role_key\r\n    FROM user_account ua\r\n    JOIN employee e       ON e.employee_id = ua.employee_id\r\n    JOIN business_role br ON br.role_id = e.business_role_id\r\n    WHERE ua.user_id = p_acting_user_id;\r\n\r\n    IF v_acting_role_key != 'ADMIN' THEN\r\n        RAISE EXCEPTION 'Permission denied: only ADMIN can change roles.';\r\n    END IF;\r\n\r\n    IF v_acting_emp = p_target_emp_id THEN\r\n        -- Check if new role is still ADMIN\r\n        IF NOT EXISTS (SELECT 1 FROM business_role WHERE role_id = p_new_role_id AND role_key = 'ADMIN') THEN\r\n            RAISE EXCEPTION 'Self-demotion not allowed.';\r\n        END IF;\r\n    END IF;\r\n\r\n    UPDATE public.employee\r\n    SET business_role_id = p_new_role_id\r\n    WHERE employee_id = p_target_emp_id;\r\n\r\n    IF NOT FOUND THEN\r\n        RAISE EXCEPTION 'Employee ID % not found.', p_target_emp_id;\r\n    END IF;\r\nEND;\r\n$function$\n"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fn_log_role_change()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    v_old_role VARCHAR;\r\n    v_new_role VARCHAR;\r\nBEGIN\r\n    SELECT display_name INTO v_old_role FROM public.business_role WHERE role_id = OLD.business_role_id;\r\n    SELECT display_name INTO v_new_role FROM public.business_role WHERE role_id = NEW.business_role_id;\r\n\r\n    INSERT INTO public.system_activity_log\r\n        (action, module, target_table, target_id, old_values, new_values, description)\r\n    VALUES (\r\n        'UPDATE',\r\n        'SETTINGS',\r\n        'employee',\r\n        NEW.employee_id,\r\n        jsonb_build_object('business_role_id', OLD.business_role_id, 'role', v_old_role),\r\n        jsonb_build_object('business_role_id', NEW.business_role_id, 'role', v_new_role),\r\n        'Role changed from ' || COALESCE(v_old_role, '?') || ' to ' || COALESCE(v_new_role, '?') ||\r\n        ' for employee ID ' || NEW.employee_id\r\n    );\r\n    RETURN NULL;\r\nEND;\r\n$function$\n"
  }
]

[
  {
    "trigger_definition": "CREATE TRIGGER trg_auto_update_balance AFTER INSERT ON public.transaction FOR EACH ROW EXECUTE FUNCTION fn_update_bank_balance()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_update_contact_ledger AFTER INSERT ON public.transaction FOR EACH ROW EXECUTE FUNCTION fn_update_contact_ledger()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_aftersaleinsert AFTER INSERT ON public.sales FOR EACH ROW EXECUTE FUNCTION fn_after_sale_insert()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_brute_force_check AFTER INSERT ON public.user_login_log FOR EACH ROW EXECUTE FUNCTION fn_check_brute_force()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_module_toggle_audit AFTER UPDATE OF is_enabled ON public.system_config FOR EACH ROW EXECUTE FUNCTION fn_log_module_toggle()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_general_settings_touch BEFORE UPDATE ON public.general_settings FOR EACH ROW EXECUTE FUNCTION fn_touch_general_settings()"
  },
  {
    "trigger_definition": "CREATE TRIGGER trg_employee_role_audit AFTER UPDATE OF business_role_id ON public.employee FOR EACH ROW WHEN ((old.business_role_id IS DISTINCT FROM new.business_role_id)) EXECUTE FUNCTION fn_log_role_change()"
  }
]